const data = $input.first().json;
const issueColors = {
  expired: '#e74c3c',
  expiring_soon_5d: '#e67e22',
  sent_unsigned_7d: '#f1c40f',
  draft_unsent_5d: '#3498db'
};
const issueLabels = {
  expired: 'EXPIRADO',
  expiring_soon_5d: 'Expira en < 5d',
  sent_unsigned_7d: 'Enviado sin firmar > 7d',
  draft_unsent_5d: 'Draft sin enviar > 5d'
};
const rows = (data.rows || []).map(r => {
  const color = issueColors[r.issue_type] || '#7f8c8d';
  const label = issueLabels[r.issue_type] || r.issue_type;
  return '<tr>' +
    '<td><span style=\"background:' + color + ';color:white;padding:3px 8px;border-radius:12px;font-size:11px\">' + label + '</span></td>' +
    '<td><b>' + r.project_name + '</b></td>' +
    '<td>' + r.contract_type + '<br><small style=\"color:#7f8c8d\">' + r.title.substring(0,60) + '</small></td>' +
    '<td>' + r.status + '<br><small>' + r.days_since_generated + 'd desde generado' + (r.days_since_sent !== null ? ' • ' + r.days_since_sent + 'd desde envio' : '') + '</small></td>' +
    '<td>' + (r.expires_at ? r.expires_at.substring(0,10) + (r.days_to_expiry !== null ? '<br><small>' + r.days_to_expiry + 'd</small>' : '') : '—') + '</td>' +
    '<td>' + (r.amount_eur || '?') + ' EUR</td>' +
    '</tr>';
}).join('');
const html = '<h2>Contratos pendientes de gestionar</h2>' +
  '<p>Total: <b>' + data.issue_count + '</b>. Marcar como signed (POST /webhook/contract-signed) o cancelar.</p>' +
  '<table border=\"1\" cellpadding=\"6\" cellspacing=\"0\" style=\"border-collapse:collapse;font-family:sans-serif;font-size:13px\">' +
  '<thead><tr style=\"background:#f3f4f6\"><th>Incidencia</th><th>Proyecto</th><th>Contrato</th><th>Estado</th><th>Expira</th><th>Importe</th></tr></thead>' +
  '<tbody>' + rows + '</tbody></table>';
return [{ json: { html_body: html, count: data.issue_count } }];

